() => {
  const menuItems = document.querySelectorAll('.elementor-nav-menu--mobile .elementor-item, .e-n-menu-item-title, [class*="menu-item"] a');
  const results = [];
  menuItems.forEach(item => {
    const cs = window.getComputedStyle(item);
    const text = item.textContent.trim();
    if (text && text.length < 30) {
      results.push({
        text,
        color: cs.color,
        bg: cs.backgroundColor,
        classes: item.className,
        parentClasses: item.parentElement?.className || ''
      });
    }
  });
  return JSON.stringify(results, null, 2);
}

() => {
  // Find the "Atuação" link in the mobile menu that's currently open and check its styles + all CSS rules
  const links = document.querySelectorAll('.elementor-nav-menu--dropdown .elementor-item');
  let result = [];
  for (const link of links) {
    const text = link.textContent.trim();
    if (text === 'Atuação') {
      const cs = window.getComputedStyle(link);
      // Also check pseudo-states via matching CSS rules
      const sheets = document.styleSheets;
      const matchingRules = [];
      for (const sheet of sheets) {
        try {
          for (const rule of sheet.cssRules) {
            if (rule.selectorText && rule.selectorText.includes('elementor-item') && 
                (rule.selectorText.includes('active') || rule.selectorText.includes('focus') || rule.selectorText.includes('hover'))) {
              if (rule.style.color) {
                matchingRules.push({sel: rule.selectorText, color: rule.style.color, src: sheet.href || 'inline'});
              }
            }
          }
        } catch(e) {}
      }
      result.push({
        text, 
        computedColor: cs.color,
        computedBg: cs.backgroundColor,
        classes: link.className,
        parentClasses: link.parentElement.className,
        matchingActiveRules: matchingRules.slice(0, 20)
      });
      break;
    }
  }
  return JSON.stringify(result, null, 2);
}

