() => {
  const dropdown = document.querySelector('.elementor-nav-menu--dropdown');
  if (!dropdown) return 'dropdown not found';
  const cs = window.getComputedStyle(dropdown);
  return JSON.stringify({
    headerTxtHover: cs.getPropertyValue('--header-txt-hover'),
    headerTxtActive: cs.getPropertyValue('--header-txt-active'),
    menuMobileBg: cs.getPropertyValue('--menu-mobile-background'),
    menuMobileBgHover: cs.getPropertyValue('--menu-mobile-background-hover'),
    accentColor: cs.getPropertyValue('--accent-color'),
  });
}

