() => {
  // Check which CSS rule is winning for the highlighted Atuação
  const link = document.querySelector('.elementor-nav-menu--dropdown .elementor-item.highlighted');
  if (!link) return 'no highlighted element found';

  const sheets = document.styleSheets;
  const matchingRules = [];
  for (const sheet of sheets) {
    try {
      for (const rule of sheet.cssRules) {
        if (rule.selectorText && rule.selectorText.includes('highlighted')) {
          if (rule.style.color) {
            matchingRules.push({
              sel: rule.selectorText.substring(0, 150),
              color: rule.style.color,
              priority: rule.style.getPropertyPriority('color'),
              src: (sheet.href || 'inline').substring(0, 80)
            });
          }
        }
      }
    } catch(e) {}
  }
  return JSON.stringify(matchingRules, null, 2);
}

