    font-size         : 16px;
    scrollbar-gutter  : stable;
    scroll-behavior   : smooth;
    scrollbar-color   : var(--e-global-color-accent, #47DEA8) var(--background-offwhite, #DEDDD1);
    scrollbar-width   : thin;
}

@media (prefers-reduced-motion: no-preference) {
    :has(:target) {
        scroll-behavior   : smooth;
        scroll-padding-top: 3rem;
    }
}

html body.elementor-default {
    background-color: var(--ucpa-color-offwhite);
    overflow-x      : hidden;
    position        : relative;
}

@media (max-width: 768px) {
    html, body {
        overflow-x: hidden;
    }
}

html body.elementor-kit-2553.elementor-page-26826 {
    background-color: var(--ucpa-color-offwhite);
}

/* --- 2.2 Tipografia --- */
h1, h2, h3, h4, h5, h6 {
    text-wrap: balance;
}

#content .tituloPagina {
    margin-top: 5rem;
}

figcaption {
    text-align: center;
    color     : var(--e-global-color-text);
}

/* --- 2.3 Links --- */
html body a[href*="mailto"]:hover {
    color: currentColor;
}

.elementor-kit-2553 a:hover {
    color: var(--e-global-color-text);
}

/* Widget Bureau SVG: preserva cor no hover para não afetar fill:currentColor */
.elementor-widget-bureau_svg a:hover {
    color: inherit !important;
}

/* --- 2.4 Seleção de Texto --- */
::selection {
    background-color: var(--ucpa-color-white);
    color           : var(--ucpa-color-accent);
}

@supports (color: color-mix(in oklch, black 50%, white)) {
    ::selection {
        background-color: color-mix(in oklch, var(--ucpa-color-main) 90%, black 10%);
        color           : color-mix(in oklch, var(--ucpa-color-main) 10%, white 90%);
    }
}

/* --- 2.5 Outline --- */
* {
    outline-color: var(--e-global-color-accent);
}

/* --- 2.6 Scrollbar --- */
::-webkit-scrollbar {
    width : 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: var(--background-offwhite, #DEDDD1);
}

::-webkit-scrollbar-thumb {
    background   : var(--background-invertido, #C02975);
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: color-mix(in lab, var(--background-invertido, #C02975) 75%, black 25%);
}


/* ==========================================================================
   3. COMPONENTES
   ========================================================================== */

/* --- 3.1 Labels --- */
html body.elementor-kit-2553 label {
    color: var(--ucpa-color-main, #000);
}

