() => {
  const link = document.querySelector('.elementor-nav-menu--dropdown .elementor-item.highlighted');
  if (!link) return 'no highlighted element';

  // Check all rules that match this element and set color
  const sheets = document.styleSheets;
  const matchingRules = [];
  for (const sheet of sheets) {
    try {
      for (const rule of sheet.cssRules) {
        if (rule.selectorText && link.matches(rule.selectorText) && rule.style.color) {
          matchingRules.push({
            sel: rule.selectorText.substring(0, 200),
            color: rule.style.color,
            important: rule.style.getPropertyPriority('color'),
            src: (sheet.href || 'inline').substring(0, 100)
          });
        }
      }
    } catch(e) {}
  }
  return JSON.stringify(matchingRules, null, 2);
}

